import * as fs from "fs";
import * as path from "path";
import { fileURLToPath } from "url";
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const LESSONS_DIR = path.join(__dirname, "../client/src/data/lessons");
function escapeStr(s: string): string { return s.replace(/\\/g, "\\\\").replace(/`/g, "\\`").replace(/"/g, '\\"').replace(/\n/g, "\\n"); }
function buildLS(l: any): string {
  const li: string[] = [];
  li.push(`    title: "${escapeStr(l.title)}",`);
  li.push(`    cellular: { title: "${escapeStr(l.cellular.title)}", content: "${escapeStr(l.cellular.content)}" },`);
  li.push(`    riskFactors: [${l.riskFactors.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
  li.push(`    diagnostics: [${l.diagnostics.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
  li.push(`    management: [${l.management.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
  li.push(`    nursingActions: [${l.nursingActions.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
  li.push(`    assessmentFindings: [${l.assessmentFindings.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
  li.push(`    signs: { left: [${l.signs.left.map((r:string) => `"${escapeStr(r)}"`).join(",")}], right: [${l.signs.right.map((r:string) => `"${escapeStr(r)}"`).join(",")}] },`);
  li.push(`    medications: [${l.medications.map((m:any) => `{ name: "${escapeStr(m.name)}", type: "${escapeStr(m.type)}", action: "${escapeStr(m.action)}", sideEffects: "${escapeStr(m.sideEffects)}", contra: "${escapeStr(m.contra)}", pearl: "${escapeStr(m.pearl)}" }`).join(",")}],`);
  li.push(`    pearls: [${l.pearls.map((r:string) => `"${escapeStr(r)}"`).join(",")}],`);
  li.push(`    quiz: [${l.quiz.map((q:any) => `{ question: "${escapeStr(q.question)}", options: [${q.options.map((o:string) => `"${escapeStr(o)}"`).join(",")}], correct: ${q.correct}, rationale: "${escapeStr(q.rationale)}" }`).join(",")}]`);
  return li.join("\n    ");
}
function inject(id: string, lesson: any): boolean {
  const files = fs.readdirSync(LESSONS_DIR).filter(f => f.endsWith(".ts") && f !== "index.ts" && f !== "types.ts");
  for (const file of files) {
    const fp = path.join(LESSONS_DIR, file);
    let src = fs.readFileSync(fp, "utf-8");
    const re = new RegExp(`"${id}":\\s*\\{[\\s\\S]*?\\[WRITE YOUR[\\s\\S]*?\\n  \\}`, "m");
    if (re.test(src)) {
      const replacement = `"${id}": {\n    ${buildLS(lesson)}\n  }`;
      src = src.replace(re, replacement);
      fs.writeFileSync(fp, src, "utf-8");
      console.log(`  Injected: ${id} -> ${file}`);
      return true;
    }
  }
  console.log(`  NOT FOUND: ${id}`);
  return false;
}

const lessons: Record<string, any> = {
  "dic-advanced-rn": {
    title: "Disseminated Intravascular Coagulation (Advanced)",
    cellular: { title: "Pathophysiology of Consumption Coagulopathy and Simultaneous Clotting-Bleeding Cascade", content: "Disseminated intravascular coagulation (DIC) is a life-threatening acquired syndrome characterized by the paradoxical simultaneous activation of widespread intravascular coagulation and secondary fibrinolysis, resulting in microvascular thrombosis causing end-organ ischemia alongside consumption of clotting factors and platelets producing hemorrhage. DIC is never a primary diagnosis but always occurs secondary to an underlying trigger condition, most commonly sepsis (35-40% of cases), malignancy (particularly acute promyelocytic leukemia, pancreatic adenocarcinoma, and mucin-secreting tumors), obstetric catastrophes (placental abruption, amniotic fluid embolism, retained dead fetus, pre-eclampsia/HELLP syndrome), massive trauma with tissue destruction, and severe hemolytic transfusion reactions. Understanding the dual pathophysiology of clotting and bleeding occurring simultaneously is essential for nurses managing these critically ill patients. The coagulation cascade is normally maintained in a tightly regulated equilibrium between procoagulant factors, natural anticoagulant mechanisms (antithrombin III, protein C/protein S system, tissue factor pathway inhibitor), and the fibrinolytic system. In DIC, this balance is catastrophically disrupted through three interconnected pathophysiological mechanisms. The first mechanism is massive, uncontrolled activation of the tissue factor (TF) pathway. In sepsis, bacterial endotoxins (lipopolysaccharide from gram-negative organisms) and inflammatory cytokines (tumor necrosis factor-alpha, interleukin-1, interleukin-6) stimulate monocytes, macrophages, and damaged endothelial cells to express tissue factor on their surfaces. In trauma, crushed tissues release tissue factor directly into the circulation. In obstetric emergencies, placental tissue and amniotic fluid are rich sources of tissue factor. Tissue factor binds Factor VII, forming the TF-VIIa complex that activates Factor X and initiates the common pathway of coagulation, generating thrombin. The second mechanism involves thrombin generation becoming massive and uncontrolled. The enormous quantities of thrombin produced overwhelm the natural anticoagulant defenses. Antithrombin III (AT-III) is consumed faster than it can be produced, its levels dropping to critically low values. Thrombin activates protein C, but the protein C-thrombomodulin system becomes saturated and ineffective. The endothelial glycocalyx, which normally provides anticoagulant heparan sulfate proteoglycans, is damaged by inflammatory mediators, further reducing antithrombin activity. With these natural brakes failing, thrombin converts massive amounts of fibrinogen to fibrin, which deposits as microthrombi throughout the microvasculature of virtually every organ. These microthrombi obstruct capillaries and small vessels, causing ischemia and infarction in end-organs including the kidneys (acute cortical necrosis), lungs (ARDS), liver (hepatic failure), brain (altered mental status, stroke), skin (purpura fulminans, digital gangrene), and adrenal glands (Waterhouse-Friderichsen syndrome in meningococcal sepsis). The third mechanism is the secondary activation of the fibrinolytic system. As fibrin is deposited throughout the vasculature, tissue plasminogen activator (tPA) is released from damaged endothelium and converts plasminogen to plasmin. Plasmin degrades the fibrin clots, producing fibrin degradation products (FDPs) and D-dimers (specific cross-linked fibrin fragments). These FDPs themselves have anticoagulant properties: they inhibit fibrin polymerization (preventing effective clot formation), impair platelet aggregation, and interfere with thrombin activity. The result is a devastating positive feedback loop: clotting produces fibrin, fibrinolysis destroys it and releases anticoagulant FDPs, which prevent effective hemostasis while clotting continues to consume factors. The consumption of clotting factors (fibrinogen, Factor V, Factor VIII, Factor XIII) and platelets by the ongoing microvascular coagulation depletes the hemostatic reserve, producing the characteristic bleeding diathesis. Patients bleed from venipuncture sites, surgical wounds, mucosal surfaces, and body orifices because they lack sufficient platelets and clotting factors to form effective hemostatic plugs. DIC can present in two clinical forms. Acute (overt, decompensated) DIC presents dramatically with simultaneous bleeding and thrombosis, most commonly seen in sepsis, major trauma, and obstetric emergencies. The International Society on Thrombosis and Haemostasis (ISTH) DIC scoring system quantifies the degree of coagulopathy using platelet count, D-dimer/FDP elevation, prolonged prothrombin time (PT), and fibrinogen level, with a score of 5 or greater indicating overt DIC. Chronic (non-overt, compensated) DIC develops insidiously, often in malignancy, where the bone marrow and liver can partially compensate for factor consumption, and may present primarily with thrombotic complications (deep vein thrombosis, pulmonary embolism, arterial thrombosis) rather than hemorrhage. Trousseau syndrome (migratory superficial thrombophlebitis) in cancer patients is a classic manifestation of chronic DIC." },
    riskFactors: ["Sepsis and severe systemic infection (most common trigger, responsible for 35-40% of DIC cases; gram-negative organisms with endotoxin release are classic but gram-positive sepsis also triggers DIC)","Major trauma with extensive tissue destruction (releases tissue factor from crushed tissues; risk increases with injury severity score and delay to treatment)","Obstetric emergencies (placental abruption, amniotic fluid embolism, eclampsia/HELLP syndrome, retained dead fetus, septic abortion -- placental tissue is extremely rich in tissue factor)","Acute promyelocytic leukemia (APL; M3 AML -- leukemic promyelocytes release procoagulant granules and tissue factor upon cell lysis, especially during induction chemotherapy)","Solid organ malignancies (pancreatic, gastric, ovarian, and mucin-secreting adenocarcinomas; mucin directly activates Factor X independently of Factor VII)","Massive hemolytic transfusion reaction (ABO-incompatible blood; hemolyzed red cell membranes provide phospholipid surface for coagulation activation and release procoagulant substances)","Severe burns covering >35% total body surface area (massive tissue necrosis, systemic inflammatory response, and infection risk combine to trigger DIC)"],
    diagnostics: ["Platelet count (decreased and falling -- serial measurements showing progressive decline are more informative than a single value; platelets <100,000 in acute DIC, may drop to <20,000)","D-dimer and fibrin degradation products (markedly elevated -- D-dimer is the most sensitive marker for DIC; reflects ongoing fibrin formation and fibrinolysis; serial rising values confirm active process)","Prothrombin time (PT) and activated partial thromboplastin time (aPTT) (prolonged -- reflects consumption of clotting factors; PT is included in the ISTH DIC scoring system)","Fibrinogen level (decreased -- normally 200-400 mg/dL; levels <100 mg/dL indicate severe consumption; however fibrinogen is an acute phase reactant and may be 'normal' early despite consumption)","ISTH DIC scoring system (assigns points for platelet count, D-dimer elevation, PT prolongation, and fibrinogen level; score >=5 indicates overt DIC; serial scoring tracks progression or resolution)","Peripheral blood smear (schistocytes -- fragmented red blood cells sheared by fibrin strands in the microvasculature; presence confirms microangiopathic hemolytic anemia associated with DIC)","Antithrombin III level (decreased due to consumption -- levels <60% correlate with more severe DIC and poorer prognosis; may guide antithrombin replacement therapy)"],
    management: ["Treat the underlying cause aggressively (antibiotics for sepsis, delivery for obstetric causes, chemotherapy with ATRA for APL, surgical control of hemorrhage in trauma -- DIC will not resolve until the trigger is removed)","Platelet transfusion to maintain count >50,000 in actively bleeding patients or >20,000 prophylactically (each platelet unit raises count approximately 5,000-10,000; transfuse for active hemorrhage or before invasive procedures)","Fresh frozen plasma (FFP) 10-15 mL/kg to replace consumed clotting factors in actively bleeding patients with prolonged PT/aPTT (contains all coagulation factors, fibrinogen, and natural anticoagulants including antithrombin)","Cryoprecipitate to replace fibrinogen when levels fall below 100 mg/dL (each unit of cryoprecipitate raises fibrinogen by approximately 5-10 mg/dL; typical dose is 10 units; also provides Factor VIII and Factor XIII)","Heparin anticoagulation considered in chronic/compensated DIC with predominantly thrombotic manifestations (low-dose unfractionated heparin 5-10 units/kg/hour; controversial in acute DIC with hemorrhage)","Tranexamic acid (antifibrinolytic) considered only if life-threatening hemorrhage persists despite aggressive factor replacement AND primary fibrinolysis is confirmed (use with extreme caution -- blocking fibrinolysis in DIC with ongoing microvascular thrombosis can worsen organ ischemia)"],
    nursingActions: ["Monitor for bleeding from ALL sites simultaneously: IV insertion sites (oozing around catheters), surgical incisions/wounds, oral mucosa (gingival bleeding), nasopharynx (epistaxis), GI tract (hematemesis, melena, hematochezia), urinary tract (hematuria), respiratory tract (hemoptysis), and skin (petechiae, purpura, ecchymoses)","Perform neurological assessments every 1-2 hours (altered mental status, decreasing Glasgow Coma Scale, pupil changes, focal neurological deficits may indicate intracranial hemorrhage or cerebral microthrombi -- report changes immediately)","Monitor coagulation studies serially (platelet count, PT/INR, aPTT, fibrinogen, D-dimer every 4-6 hours during acute phase) and communicate trends to the medical team using the ISTH DIC score to quantify severity","Administer blood products as ordered: platelets, FFP, cryoprecipitate -- use blood warmers to prevent hypothermia (hypothermia impairs coagulation and worsens DIC); verify ABO compatibility; monitor for transfusion reactions which could worsen DIC","Minimize invasive procedures and venipunctures (consolidate blood draws, use existing lines when possible); apply prolonged pressure (at least 10-15 minutes) to all puncture sites; avoid intramuscular injections, rectal temperatures, and unnecessary catheter insertions","Assess for signs of end-organ ischemia from microvascular thrombosis: decreased urine output or anuria (renal cortical necrosis), worsening hypoxemia or ARDS (pulmonary microthrombi), acral cyanosis and digital ischemia (peripheral microthrombi), hepatic dysfunction (rising transaminases, jaundice)","Monitor fluid balance meticulously -- massive blood product transfusion can cause volume overload; assess for pulmonary edema, rising CVP, and worsening oxygenation; coordinate diuretic therapy between transfusion episodes","Document skin assessment thoroughly including mapping of new petechiae, purpura, and ecchymoses; photograph purpura fulminans progression; assess extremities for acral cyanosis, mottling, and digital gangrene requiring surgical consultation"],
    assessmentFindings: ["Bleeding from multiple unrelated sites simultaneously (hallmark of DIC -- oozing from IV sites, surgical wounds, and mucosal surfaces occurring together is highly suspicious)","Petechiae, purpura, and ecchymoses (reflect thrombocytopenia and coagulopathy; petechiae on dependent areas and pressure points appear first)","Purpura fulminans (large, irregular areas of skin necrosis with sharp borders caused by microvascular thrombosis and hemorrhagic infarction of the skin -- pathognomonic for severe DIC, especially in meningococcemia)","Acral cyanosis and digital ischemia (blue-purple discoloration of fingers, toes, ears, and nose from microvascular thrombosis; may progress to frank gangrene requiring amputation)","Altered mental status ranging from confusion to obtundation (from cerebral microthrombi, intracranial hemorrhage, or systemic hypoperfusion)","Oliguria or anuria (from renal cortical necrosis caused by glomerular microthrombi; may require renal replacement therapy)","Tachycardia, hypotension, and signs of hemorrhagic shock (from combined blood loss at multiple sites and impaired hemostasis)"],
    signs: { left: ["Mild thrombocytopenia (100,000-150,000) with mildly elevated D-dimer","Oozing from a single venipuncture site that responds to prolonged pressure","Small scattered petechiae on lower extremities","Mildly prolonged PT (1-3 seconds above normal) with normal fibrinogen","Subtle laboratory derangement without clinical bleeding (non-overt DIC score <5)"], right: ["Massive hemorrhage from multiple sites simultaneously unresponsive to transfusion","Purpura fulminans with extensive skin necrosis and digital gangrene requiring amputation","Intracranial hemorrhage causing herniation and neurological devastation","Refractory hemorrhagic shock with cardiovascular collapse despite massive transfusion protocol","Multi-organ failure (renal, hepatic, pulmonary, neurological) from combined microvascular thrombosis and hemorrhage"] },
    medications: [
      { name: "Heparin (unfractionated)", type: "Anticoagulant (indirect thrombin inhibitor for thrombosis-predominant DIC)", action: "Binds to and potentiates antithrombin III (AT-III), accelerating its inhibition of thrombin (Factor IIa) and Factor Xa by 1000-fold. In chronic/compensated DIC where thrombotic manifestations predominate (Trousseau syndrome, DVT, PE, arterial thrombosis), low-dose heparin (5-10 units/kg/hour) aims to interrupt the ongoing coagulation activation and reduce microvascular thrombosis. Heparin does NOT dissolve existing thrombi but prevents propagation and new formation. Its use in DIC is controversial and requires careful risk-benefit analysis: in predominantly thrombotic DIC (chronic, cancer-associated), benefits often outweigh risks; in acute hemorrhagic DIC, heparin may worsen bleeding and is generally contraindicated.", sideEffects: "Hemorrhage (major risk, especially in DIC patients with existing coagulopathy and thrombocytopenia); heparin-induced thrombocytopenia type II (HIT -- paradoxical prothrombotic state mediated by anti-PF4/heparin antibodies; incidence 1-5% with UFH); injection site hematoma; osteoporosis with prolonged use; hyperkalemia (aldosterone suppression)", contra: "Active major hemorrhage (absolute contraindication in bleeding-predominant DIC); severe thrombocytopenia <20,000 (increased hemorrhage risk); history of heparin-induced thrombocytopenia (use alternative anticoagulant); inability to monitor aPTT or anti-Xa levels adequately; uncontrolled hypertension", pearl: "Heparin requires adequate AT-III to function -- in severe DIC, AT-III is consumed and levels may be <60%, rendering heparin ineffective; if heparin is not achieving therapeutic effect, check AT-III level and consider AT-III concentrate replacement before increasing heparin dose; protamine sulfate reverses heparin (1 mg protamine per 100 units heparin given in previous 2-3 hours); never give heparin in actively hemorrhaging acute DIC without explicit clinical justification" },
      { name: "Cryoprecipitate", type: "Blood product (concentrated fibrinogen and clotting factor replacement)", action: "Cryoprecipitate is prepared by thawing fresh frozen plasma at 1-6 degrees Celsius and collecting the cold-insoluble precipitate, which is enriched in fibrinogen (150-250 mg per unit), Factor VIII (80-120 IU per unit), Factor XIII, von Willebrand factor, and fibronectin. In DIC, the primary indication is fibrinogen replacement when levels fall below 100 mg/dL due to consumption. Fibrinogen is the substrate for fibrin clot formation, and its depletion renders hemostasis impossible regardless of other clotting factor levels. Each unit of cryoprecipitate raises plasma fibrinogen by approximately 5-10 mg/dL in an average adult. A standard dose of 10 pooled units raises fibrinogen by 50-100 mg/dL, targeting a level above 150 mg/dL in actively bleeding patients.", sideEffects: "Allergic/anaphylactic transfusion reactions (urticaria, fever, rigors; rare anaphylaxis); transfusion-associated circulatory overload (TACO -- especially with multiple concurrent blood product transfusions in DIC); transfusion-related acute lung injury (TRALI); febrile non-hemolytic reactions; theoretical infectious disease transmission risk (screened but not pathogen-reduced)", contra: "No absolute contraindication when fibrinogen <100 mg/dL in active DIC with hemorrhage; relative contraindications include known severe allergic reaction to plasma products; volume overload concern (each unit is approximately 15 mL, 10-unit pool is 150 mL); primary fibrinolysis without DIC (use of blood products without addressing cause may worsen condition)", pearl: "Fibrinogen is an acute-phase reactant and may be 'normal' (200-400 mg/dL) early in DIC even when consumption is occurring -- what matters is the TREND; a fibrinogen that drops from 500 to 200 may still represent significant consumption; check fibrinogen every 4-6 hours during acute DIC; target fibrinogen >150 mg/dL in active hemorrhage; cryoprecipitate must be ABO-compatible (contains anti-A and anti-B antibodies); thaw at 30-37 degrees and transfuse within 6 hours of thawing; do not refreeze" },
      { name: "Tranexamic acid (TXA)", type: "Antifibrinolytic agent (lysine analog that inhibits plasminogen activation)", action: "Tranexamic acid is a synthetic lysine analog that competitively binds to the lysine-binding sites on plasminogen and plasmin, preventing their attachment to fibrin and blocking the conversion of plasminogen to plasmin by tissue plasminogen activator (tPA). By inhibiting fibrinolysis, TXA stabilizes formed fibrin clots and reduces bleeding from clot dissolution. In DIC, TXA use is extremely controversial and is reserved for specific situations where life-threatening hemorrhage persists despite aggressive factor replacement AND where the clinical picture is dominated by primary hyperfibrinolysis rather than microvascular thrombosis. The concern is that blocking fibrinolysis in a patient with ongoing microvascular coagulation (the core pathology of DIC) may catastrophically worsen organ ischemia by preventing the natural dissolution of obstructive microthrombi.", sideEffects: "Nausea, vomiting, diarrhea (most common); thrombotic complications (DVT, PE, arterial thrombosis, renal cortical necrosis -- the MAJOR CONCERN in DIC where microvascular thrombosis is already occurring); seizures (particularly at high doses or in renal impairment -- TXA crosses the blood-brain barrier and is a GABA receptor antagonist); hypotension with rapid IV administration; visual disturbances (rare)", contra: "Active intravascular thrombosis or high risk of thrombosis (RELATIVE CONTRAINDICATION -- DIC inherently involves microvascular thrombosis, making TXA use inherently risky); subarachnoid hemorrhage (increased risk of cerebral vasospasm and ischemia); severe renal impairment (TXA is renally excreted; dose reduction required); history of seizure disorder (lowers seizure threshold); upper urinary tract bleeding (risk of obstructive ureteral clot)", pearl: "TXA in DIC is a LAST RESORT used only when hemorrhage is immediately life-threatening and refractory to massive blood product replacement -- NEVER use TXA as routine therapy in DIC; if used, give 1g IV over 10 minutes (do NOT give as rapid bolus -- causes hypotension); the decision to use TXA in DIC should involve hematology consultation and careful consideration that blocking fibrinolysis may worsen organ ischemia from unresolved microthrombi; in trauma-associated DIC, the CRASH-2 trial supports early TXA use within 3 hours of injury to reduce hemorrhagic death" }
    ],
    pearls: ["DIC is ALWAYS secondary to an underlying trigger -- the most important treatment is addressing the primary cause; antibiotics for sepsis, delivery of the fetus/placenta in obstetric DIC, ATRA for acute promyelocytic leukemia; DIC will not resolve until the trigger is eliminated","The ISTH DIC scoring system (platelet count + D-dimer + PT prolongation + fibrinogen level, score >=5 = overt DIC) should be calculated serially every 6-12 hours to monitor progression or resolution and guide transfusion thresholds","Simultaneous bleeding AND clotting is the pathophysiological hallmark of DIC -- patients may bleed from venipuncture sites while simultaneously developing digital gangrene from microvascular thrombosis in their fingers; do not assume DIC is only a bleeding disorder","Fibrinogen is an acute-phase reactant with normal levels of 200-400 mg/dL -- in DIC, a 'normal' fibrinogen of 250 that was 500 yesterday represents significant consumption and should trigger concern; serial trending is more informative than single values","Schistocytes (fragmented red blood cells) on peripheral blood smear confirm microangiopathic hemolytic anemia from fibrin strand shearing of RBCs in the microvasculature -- their presence strongly supports the diagnosis of DIC when combined with thrombocytopenia and coagulopathy","Purpura fulminans (large, sharply demarcated areas of hemorrhagic skin necrosis) is virtually pathognomonic for severe DIC and is caused by dermal microvascular thrombosis with hemorrhagic infarction -- it requires immediate ICU-level care and often leads to limb amputation","Never give intramuscular injections, perform rectal examinations, or insert rectal thermometers in patients with DIC -- these can cause uncontrollable hemorrhage at the puncture or mucosal disruption sites due to the severe coagulopathy"],
    quiz: [
      { question: "A critically ill patient with gram-negative sepsis develops oozing from IV sites, petechiae, and a falling platelet count. Labs show elevated D-dimer, prolonged PT, and fibrinogen dropping from 400 to 120 mg/dL. What is the most likely diagnosis?", options: ["Immune thrombocytopenic purpura (ITP) from antibiotic therapy","Disseminated intravascular coagulation (DIC) triggered by sepsis","Heparin-induced thrombocytopenia (HIT) type II","Thrombotic thrombocytopenic purpura (TTP)"], correct: 1, rationale: "This presentation is classic for sepsis-triggered DIC: the combination of bleeding from multiple sites (oozing from IV sites, petechiae), falling platelet count (consumption), elevated D-dimer (fibrin formation and lysis), prolonged PT (clotting factor consumption), and declining fibrinogen (converted to fibrin microthrombi) in the setting of gram-negative sepsis. ITP would show isolated thrombocytopenia without coagulopathy. HIT requires heparin exposure. TTP characteristically shows ADAMTS13 deficiency with severe thrombocytopenia but normal coagulation studies." },
      { question: "A nurse is transfusing cryoprecipitate to a patient with acute DIC whose fibrinogen level is 75 mg/dL. What is the most important nursing consideration?", options: ["Cryoprecipitate can be administered without ABO compatibility testing because it contains no red blood cells","The target fibrinogen level is >150 mg/dL in actively bleeding patients, and serial fibrinogen levels should be monitored every 4-6 hours to guide repeat dosing","Cryoprecipitate should be infused slowly over 4 hours to prevent fluid overload","Fibrinogen levels below 200 mg/dL are always abnormal and require immediate replacement regardless of clinical context"], correct: 1, rationale: "In actively bleeding DIC patients, the target fibrinogen level is >150 mg/dL. A level of 75 mg/dL represents severe fibrinogen depletion from consumption. Serial monitoring every 4-6 hours is essential because DIC is a dynamic process with ongoing consumption. Cryoprecipitate DOES require ABO compatibility (it contains plasma with anti-A/anti-B antibodies). It should be infused within 6 hours of thawing, not over 4 hours. While fibrinogen <200 may suggest consumption, it is an acute-phase reactant, and the clinical context (DIC with active bleeding) determines urgency." },
      { question: "A patient with cancer-associated chronic DIC presents with a new deep vein thrombosis. The medical team is considering heparin anticoagulation. What must the nurse monitor before and during heparin therapy?", options: ["Only the aPTT every 6 hours is needed to monitor heparin effectiveness","Antithrombin III (AT-III) levels should be checked because AT-III depletion in DIC renders heparin ineffective, and platelet counts must be monitored for heparin-induced thrombocytopenia","Heparin requires no monitoring in chronic DIC because the doses used are subtherapeutic","Only fibrinogen levels need monitoring because heparin primarily affects fibrinogen metabolism"], correct: 1, rationale: "Heparin works by potentiating antithrombin III (AT-III), but in DIC, AT-III is consumed and may be severely depleted (<60% of normal). If AT-III levels are inadequate, heparin will be ineffective regardless of dose, and AT-III concentrate replacement may be needed. Additionally, heparin-induced thrombocytopenia (HIT) type II must be monitored with serial platelet counts (typically checked every 2-3 days for the first 14 days), as HIT would cause a paradoxical worsening of thrombosis. Standard monitoring also includes aPTT or anti-Xa levels." }
    ]
  },

  "diffuse-alveolar-hemorrhage-rn": {
    title: "Diffuse Alveolar Hemorrhage",
    cellular: { title: "Pathophysiology of Alveolar Capillary Disruption and Pulmonary Hemorrhage", content: "Diffuse alveolar hemorrhage (DAH) is a life-threatening pulmonary emergency characterized by bleeding originating from the pulmonary microvasculature (alveolar capillaries, arterioles, and venules) into the alveolar spaces, producing the classic clinical triad of hemoptysis, diffuse bilateral pulmonary infiltrates on chest imaging, and progressive anemia. DAH is not a single disease but a clinical syndrome with numerous underlying etiologies, all of which share the common final pathway of disruption of the alveolar-capillary basement membrane leading to hemorrhage into the alveolar compartment. The alveolar-capillary membrane is an exquisitely thin barrier (approximately 0.2-0.5 micrometers) composed of three layers: the alveolar epithelium (type I pneumocytes that facilitate gas exchange and type II pneumocytes that produce surfactant), the shared basement membrane, and the capillary endothelium. This membrane normally allows efficient gas exchange while preventing blood from entering the alveolar space. In DAH, this barrier is disrupted through one of three histopathological patterns. The most common pattern is pulmonary capillaritis, which accounts for approximately 60-70% of DAH cases. Pulmonary capillaritis is a small-vessel vasculitis affecting the alveolar capillaries, characterized by neutrophilic infiltration of the capillary walls (neutrophilic interstitial pneumonitis), fibrinoid necrosis of the vessel walls, and destruction of the alveolar-capillary basement membrane. The infiltrating neutrophils release reactive oxygen species, proteolytic enzymes (elastase, collagenase, myeloperoxidase), and neutrophil extracellular traps (NETs) that directly damage the capillary endothelium and basement membrane, creating gaps through which red blood cells extravasate into the alveolar space. The most important causes of pulmonary capillaritis are ANCA-associated vasculitides: granulomatosis with polyangiitis (GPA, formerly Wegener granulomatosis) associated with cytoplasmic ANCA (c-ANCA/PR3-ANCA), microscopic polyangiitis (MPA) associated with perinuclear ANCA (p-ANCA/MPO-ANCA), and eosinophilic granulomatosis with polyangiitis (EGPA, formerly Churg-Strauss syndrome). Anti-glomerular basement membrane (anti-GBM) disease (Goodpasture disease) produces both DAH and rapidly progressive glomerulonephritis through autoantibodies targeting the alpha-3 chain of type IV collagen, which is present in both pulmonary and glomerular basement membranes. Systemic lupus erythematosus (SLE) causes DAH through immune complex deposition in alveolar capillaries (lupus pneumonitis) in approximately 2-5% of SLE patients, with a mortality rate of 50-90%. The second histopathological pattern is bland pulmonary hemorrhage (without capillaritis), where bleeding occurs through an intact but stressed alveolar-capillary membrane. This pattern is seen in coagulopathies (DIC, anticoagulant therapy, thrombocytopenia), mitral stenosis (chronically elevated pulmonary venous pressures cause capillary stress failure), and idiopathic pulmonary hemosiderosis (a rare condition predominantly in children where recurrent episodes of bland hemorrhage lead to iron deposition and pulmonary fibrosis). The third pattern is diffuse alveolar damage (DAD), the pathological correlate of ARDS, where the inflammatory destruction of the alveolar-capillary membrane causes hemorrhagic pulmonary edema. Regardless of the underlying mechanism, the consequences of alveolar hemorrhage are devastating. Blood filling the alveoli directly impairs gas exchange by creating a diffusion barrier for oxygen and carbon dioxide, producing ventilation-perfusion mismatch and shunt physiology. The hemoglobin released from extravasated red blood cells is converted by alveolar macrophages into hemosiderin, and the presence of hemosiderin-laden macrophages (siderophages) in bronchoalveolar lavage (BAL) fluid is a key diagnostic finding. Surfactant is diluted and inactivated by the hemorrhagic fluid, further compromising alveolar stability and promoting atelectasis. If hemorrhage continues, the patient develops progressive hypoxemic respiratory failure requiring mechanical ventilation. Recurrent episodes of DAH lead to pulmonary fibrosis from the organization of blood and inflammatory debris within the alveolar spaces." },
    riskFactors: ["ANCA-associated vasculitis (granulomatosis with polyangiitis, microscopic polyangiitis -- the most common causes of DAH through pulmonary capillaritis; GPA c-ANCA/PR3 positive, MPA p-ANCA/MPO positive)","Anti-GBM disease (Goodpasture syndrome -- autoantibodies against alpha-3 chain of type IV collagen target both pulmonary and glomerular basement membranes; classically affects young male smokers)","Systemic lupus erythematosus (DAH occurs in 2-5% of SLE patients; carries 50-90% mortality; often associated with lupus nephritis and high disease activity)","Anticoagulant therapy or coagulopathy (warfarin, DOACs, heparin, DIC, severe thrombocytopenia -- bleeding through stressed but intact capillary membrane)","Bone marrow transplant (DAH occurs in 5-20% of allogeneic HSCT recipients, typically in the engraftment period; mortality exceeds 70%)","Cocaine inhalation (crack cocaine causes direct alveolar capillary injury and vasospasm leading to hemorrhage)","Mitral stenosis with elevated pulmonary venous pressures (chronic capillary stress failure from elevated pulmonary capillary wedge pressure)"],
    diagnostics: ["Bronchoalveolar lavage (BAL) with sequential aliquot analysis (gold standard -- progressively bloodier return on sequential aliquots confirms alveolar rather than airway source; hemosiderin-laden macrophages >20% of total macrophages confirms DAH; Prussian blue staining identifies siderophages)","Chest X-ray and CT chest (bilateral diffuse alveolar opacities, ground-glass pattern, typically bilateral and perihilar; may progress to consolidation; subpleural sparing is characteristic)","Complete blood count with serial hemoglobin monitoring (dropping hemoglobin/hematocrit without obvious external bleeding source in context of pulmonary infiltrates strongly suggests DAH)","ANCA panel (c-ANCA/PR3 for GPA, p-ANCA/MPO for MPA -- essential for identifying vasculitis as the underlying cause of DAH)","Anti-GBM antibody level (diagnoses Goodpasture disease; order in any DAH with concurrent glomerulonephritis)","Urinalysis with microscopy (red blood cell casts and dysmorphic RBCs indicate glomerulonephritis suggesting pulmonary-renal syndrome from vasculitis or anti-GBM disease)","DLCO (diffusing capacity for carbon monoxide) -- paradoxically INCREASED in acute DAH because intra-alveolar hemoglobin absorbs CO; rising DLCO >30% above baseline during active hemorrhage is diagnostic"],
    management: ["High-dose pulse methylprednisolone 500-1000 mg IV daily for 3-5 days for immune-mediated DAH (vasculitis, anti-GBM disease, SLE lupus pneumonitis -- suppresses the inflammatory cascade destroying alveolar capillaries)","Cyclophosphamide 15 mg/kg IV (or oral 2 mg/kg/day) for ANCA-associated vasculitis causing DAH (potent immunosuppressive alkylating agent that depletes lymphocytes and suppresses antibody production; used with pulse steroids for remission induction)","Plasmapheresis (plasma exchange) for anti-GBM disease and severe ANCA-associated DAH (physically removes pathogenic autoantibodies -- anti-GBM antibodies or ANCA -- from the circulation; typically 7-14 daily exchanges)","Rituximab 375 mg/m2 weekly x 4 as alternative to cyclophosphamide for ANCA-associated vasculitis (anti-CD20 monoclonal antibody depleting B lymphocytes; RAVE trial showed non-inferiority to cyclophosphamide for remission induction)","Mechanical ventilation with lung-protective strategy for severe respiratory failure (low tidal volume 6 mL/kg ideal body weight, plateau pressure <30 cmH2O, PEEP titrated to oxygenation; avoid high PEEP if possible as it may worsen hemorrhage)","Correct coagulopathy aggressively if present (reverse anticoagulation, transfuse platelets for thrombocytopenia <50,000, FFP for factor deficiency, cryoprecipitate for fibrinogen <100 mg/dL)"],
    nursingActions: ["Monitor respiratory status continuously including oxygen saturation, respiratory rate, work of breathing, and arterial blood gas trends -- DAH can progress rapidly from mild hemoptysis to fulminant respiratory failure requiring emergent intubation","Quantify and characterize hemoptysis (volume per episode, color -- bright red vs rust-colored, frequency); notify provider immediately if hemoptysis increases in volume or frequency or if sputum becomes frankly bloody","Monitor serial hemoglobin/hematocrit every 4-6 hours during active hemorrhage -- a dropping hemoglobin without obvious external bleeding in a patient with pulmonary infiltrates should raise immediate suspicion for ongoing alveolar hemorrhage","Administer pulse-dose methylprednisolone per protocol (infuse over 30-60 minutes; monitor blood pressure during infusion as rapid administration can cause hypotension; monitor blood glucose every 4-6 hours as high-dose steroids cause significant hyperglycemia)","Position patient with the bleeding lung dependent if laterality is known (prevents blood from filling the non-bleeding lung and maintains gas exchange in the healthier lung); elevate head of bed 30-45 degrees to optimize respiratory mechanics","Maintain large-bore IV access (18-gauge or larger) and have blood products readily available -- patients with DAH can deteriorate rapidly with massive hemorrhage requiring emergent transfusion; ensure type and crossmatch is current","Monitor renal function closely (serum creatinine, BUN, urine output, urinalysis) -- pulmonary-renal syndrome (concurrent DAH and glomerulonephritis) occurs in ANCA vasculitis and anti-GBM disease; report declining urine output or rising creatinine immediately","Prepare for and assist with bronchoscopy (ensure informed consent, pre-procedure labs including coagulation studies and platelet count, NPO status; during procedure monitor oxygen saturation and hemodynamics; post-procedure monitor for respiratory deterioration)"],
    assessmentFindings: ["Hemoptysis ranging from blood-streaked sputum to massive frank hemoptysis (present in approximately 65-70% of DAH cases; notably, up to 33% of patients may have NO hemoptysis despite significant alveolar hemorrhage)","Progressive dyspnea and hypoxemia (from blood filling alveolar spaces, impairing gas exchange and producing intrapulmonary shunt)","Bilateral diffuse crackles on lung auscultation (from fluid/blood in alveoli; distribution is typically bilateral and diffuse, not focal)","Dropping hemoglobin/hematocrit without obvious external bleeding source (blood sequestered in the pulmonary parenchyma may cause a hemoglobin drop of 1-4 g/dL or more over 24-48 hours)","Tachypnea and increased work of breathing (compensatory response to hypoxemia and reduced lung compliance from alveolar flooding)","Fever (may indicate underlying vasculitis or infection triggering the hemorrhage)","Concurrent renal findings suggesting pulmonary-renal syndrome (hematuria, proteinuria, rising creatinine -- seen in ANCA vasculitis and Goodpasture disease)"],
    signs: { left: ["Blood-streaked sputum with mild dyspnea on exertion","Hemoglobin stable or mildly decreased (drop <1 g/dL)","Bilateral ground-glass opacities on chest imaging without consolidation","Oxygen saturation >92% on room air","Mild crackles heard bilaterally at lung bases"], right: ["Massive hemoptysis (>500 mL/24 hours) with hemodynamic instability requiring vasopressors","Fulminant respiratory failure requiring emergent intubation and mechanical ventilation with high PEEP and FiO2","Hemoglobin dropping >3 g/dL in 24 hours requiring massive transfusion protocol","Combined DAH with rapidly progressive glomerulonephritis and acute renal failure requiring emergent dialysis","Refractory hypoxemia despite maximum ventilator support requiring consideration of ECMO"] },
    medications: [
      { name: "Methylprednisolone (Solu-Medrol)", type: "High-dose pulse corticosteroid (immunosuppressive anti-inflammatory for immune-mediated DAH)", action: "Methylprednisolone is a potent synthetic glucocorticoid that suppresses the immune-mediated destruction of alveolar capillaries through multiple mechanisms: it inhibits NF-kappaB-mediated transcription of pro-inflammatory cytokines (TNF-alpha, IL-1, IL-6, IL-8), reduces neutrophil chemotaxis and adhesion to endothelium (decreasing neutrophilic infiltration of capillary walls), suppresses T-cell and B-cell activation and proliferation, stabilizes lysosomal membranes in neutrophils (preventing release of proteolytic enzymes), and reduces vascular permeability. In DAH from vasculitis or autoimmune disease, pulse-dose methylprednisolone (500-1000 mg IV daily for 3-5 consecutive days) rapidly suppresses the inflammatory destruction of alveolar capillaries, reducing hemorrhage and allowing the damaged alveolar-capillary membrane to begin healing.", sideEffects: "Hyperglycemia (blood glucose may exceed 300 mg/dL during pulse dosing, requiring insulin management); immunosuppression with increased infection risk (bacterial, fungal, opportunistic -- particularly concerning in ICU patients already at high risk); GI bleeding (stress ulceration -- use PPI prophylaxis); psychiatric effects (insomnia, agitation, psychosis, euphoria); fluid retention and hypertension; hypokalemia; avascular necrosis of femoral head (with prolonged use); adrenal suppression requiring taper after pulse dosing", contra: "Active untreated systemic fungal infection; live vaccine administration; known hypersensitivity; use with extreme caution in active peptic ulcer disease, uncontrolled diabetes, severe osteoporosis, and psychotic disorders", pearl: "Pulse methylprednisolone should be initiated EMERGENTLY when immune-mediated DAH is suspected -- do NOT wait for biopsy or serologic confirmation; infuse each dose over 30-60 minutes (rapid bolus can cause hypotension, arrhythmia, and cardiac arrest); monitor blood glucose every 4-6 hours and expect to manage hyperglycemia with sliding-scale or infusion insulin; after completing the pulse, transition to oral prednisone 1 mg/kg/day with gradual taper over months guided by clinical response; always administer PPI for GI prophylaxis during high-dose steroid therapy" },
      { name: "Cyclophosphamide (Cytoxan)", type: "Alkylating immunosuppressive agent (remission induction for ANCA-associated vasculitis with DAH)", action: "Cyclophosphamide is a nitrogen mustard alkylating agent that forms covalent bonds with DNA by transferring alkyl groups to guanine bases, creating DNA cross-links that prevent DNA replication and transcription. This results in cell death, particularly affecting rapidly dividing cells including lymphocytes. Cyclophosphamide is a prodrug that requires hepatic activation by cytochrome P450 enzymes to its active metabolites (phosphoramide mustard and acrolein). In ANCA-associated vasculitis causing DAH, cyclophosphamide depletes both T and B lymphocytes, suppressing the autoimmune response that drives the production of ANCA antibodies and the neutrophilic capillaritis destroying alveolar vessels. It is used in combination with pulse corticosteroids for remission induction in life-threatening vasculitis.", sideEffects: "Myelosuppression (neutropenia nadir at 7-14 days -- increases infection risk significantly; monitor CBC weekly); hemorrhagic cystitis (from acrolein metabolite irritating bladder mucosa -- prevented by aggressive hydration and mesna administration); nausea and vomiting (highly emetogenic -- requires pre-treatment with ondansetron and dexamethasone); gonadal toxicity and infertility (both sexes, dose-dependent); increased malignancy risk (bladder cancer from acrolein, lymphoma, leukemia); alopecia; SIADH with hyponatremia (particularly with IV administration)", contra: "Active severe infection (cyclophosphamide will worsen immunosuppression); severe bone marrow failure or neutropenia (ANC <1500); pregnancy (teratogenic -- Category D); breastfeeding; urinary outflow obstruction (increases hemorrhagic cystitis risk); known hypersensitivity", pearl: "For IV pulse cyclophosphamide: pre-hydrate with normal saline to maintain brisk urine output; administer mesna (sodium 2-mercaptoethane sulfonate) at 60-100% of the cyclophosphamide dose in divided doses to prevent hemorrhagic cystitis (mesna binds acrolein in the bladder); hold antiemetics ready BEFORE infusion (ondansetron 8 mg IV); check CBC with differential before each pulse and hold if ANC <1500; dose-adjust for renal impairment (GFR <30: reduce dose by 25-50%); Pneumocystis jirovecii prophylaxis with TMP-SMX is mandatory during and after cyclophosphamide therapy" },
      { name: "Plasmapheresis (therapeutic plasma exchange)", type: "Extracorporeal blood purification procedure (removal of pathogenic autoantibodies)", action: "Plasmapheresis physically separates and removes the patient's plasma (which contains the pathogenic autoantibodies -- anti-GBM antibodies, ANCA, immune complexes) from the cellular blood components using either centrifugation or membrane filtration. The removed plasma is replaced with albumin (5% human albumin) or, in patients who are actively bleeding, fresh frozen plasma (FFP, which replaces coagulation factors removed during the exchange). Each treatment exchanges approximately 1-1.5 plasma volumes (approximately 3-4 liters in an average adult), removing roughly 60-70% of intravascular IgG per session. In anti-GBM disease, plasmapheresis is considered standard of care because anti-GBM antibodies are exclusively IgG and are efficiently removed, and the disease does not relapse once antibodies are cleared (unlike ANCA vasculitis). In severe ANCA-associated vasculitis with DAH, plasmapheresis is used as adjunctive therapy to rapidly reduce ANCA titers while immunosuppressive medications take effect over days to weeks.", sideEffects: "Hypotension (from rapid fluid shifts and vasovagal responses); citrate toxicity (citrate anticoagulant used in the circuit chelates calcium, causing hypocalcemia -- symptoms include perioral tingling, paresthesias, muscle cramps, tetany, arrhythmias); coagulopathy (removal of clotting factors with albumin replacement -- if using albumin rather than FFP); allergic reactions to replacement fluid (especially FFP); catheter-related complications (infection, thrombosis, hemorrhage at vascular access site); hypothermia from extracorporeal circulation", contra: "Hemodynamic instability unresponsive to vasopressors (relative -- may need to modify procedure); severe sepsis with ongoing bacteremia (removing immunoglobulins may worsen infection); severe coagulopathy with active hemorrhage when using albumin replacement (use FFP replacement instead); inability to achieve adequate vascular access", pearl: "For anti-GBM disease, plasmapheresis is URGENT and should be initiated as soon as the diagnosis is suspected (even before biopsy confirmation) because irreversible renal and pulmonary damage progresses rapidly; typical course is 14 daily exchanges for anti-GBM disease, 5-7 exchanges for ANCA vasculitis; monitor ionized calcium during procedure and replace calcium gluconate for citrate-induced hypocalcemia; when performing plasmapheresis in a patient receiving IV immunosuppressive medications (cyclophosphamide, rituximab), schedule the exchange BEFORE the drug infusion to avoid removing the drug from the circulation" }
    ],
    pearls: ["DAH classically presents as the triad of hemoptysis, bilateral diffuse infiltrates, and dropping hemoglobin -- but up to 33% of patients have NO hemoptysis despite significant alveolar hemorrhage; the absence of hemoptysis does not rule out DAH","BAL (bronchoalveolar lavage) is the diagnostic gold standard -- progressively bloodier return on sequential aliquots (increasingly hemorrhagic on aliquots 1 through 3-5) distinguishes true DAH from airway bleeding; hemosiderin-laden macrophages (siderophages) on Prussian blue staining confirm recent or recurrent hemorrhage","DLCO (diffusing capacity for carbon monoxide) is paradoxically INCREASED in acute DAH because intra-alveolar hemoglobin avidly binds CO -- this is the ONLY condition where an acutely rising DLCO is a pathological finding","The pulmonary-renal syndrome (concurrent DAH + rapidly progressive glomerulonephritis) should immediately trigger evaluation for ANCA vasculitis (GPA or MPA) and anti-GBM disease (Goodpasture) -- check ANCA, anti-GBM antibody, urinalysis with microscopy, and serum creatinine urgently","Pulse methylprednisolone (500-1000 mg IV x 3-5 days) should be initiated EMERGENTLY when immune-mediated DAH is suspected -- do not wait for biopsy or serologic confirmation; delayed treatment allows progressive alveolar capillary destruction","In anti-GBM disease, plasmapheresis is the cornerstone of therapy and should be started within 24 hours of diagnosis -- anti-GBM antibodies are IgG, efficiently removed by plasma exchange, and the disease typically does not relapse once antibodies are cleared","Position patients with lateralized hemorrhage with the BLEEDING LUNG DOWN (dependent position) to prevent blood from flooding the unaffected lung and preserve gas exchange in the non-bleeding side"],
    quiz: [
      { question: "A patient with known granulomatosis with polyangiitis (GPA) presents with hemoptysis, bilateral pulmonary infiltrates, and a hemoglobin that has dropped from 12.5 to 9.2 g/dL over 24 hours. Which diagnostic test is most important to confirm diffuse alveolar hemorrhage?", options: ["CT pulmonary angiography to rule out pulmonary embolism","Bronchoalveolar lavage (BAL) showing progressively bloodier sequential aliquots and hemosiderin-laden macrophages","Sputum culture and gram stain to rule out pneumonia with hemoptysis","Echocardiogram to evaluate for mitral stenosis causing pulmonary hemorrhage"], correct: 1, rationale: "BAL is the gold standard for confirming DAH. The finding of progressively bloodier return on sequential aliquots (increasingly hemorrhagic from aliquots 1 through 3-5) confirms the alveolar source of hemorrhage and distinguishes DAH from airway bleeding. The presence of hemosiderin-laden macrophages (siderophages >20%) on Prussian blue staining confirms that hemorrhage has been occurring for at least 48-72 hours. In this patient with known GPA and the classic triad (hemoptysis, bilateral infiltrates, dropping hemoglobin), BAL confirms the diagnosis and helps exclude infection." },
      { question: "A nurse is caring for a patient with diffuse alveolar hemorrhage from anti-GBM disease. The patient is receiving plasmapheresis and reports perioral tingling and finger numbness during the procedure. What is the most likely cause and appropriate nursing action?", options: ["Allergic reaction to the replacement fluid -- stop the procedure and administer epinephrine","Citrate toxicity causing hypocalcemia -- notify the physician and administer calcium gluconate as ordered while monitoring ionized calcium","Hypovolemia from excessive plasma removal -- increase the replacement fluid rate","Heparin-induced bleeding -- reverse anticoagulation with protamine sulfate"], correct: 1, rationale: "Citrate is used as the anticoagulant in the plasmapheresis circuit and is infused into the patient during the procedure. Citrate chelates ionized calcium, causing hypocalcemia. Classic symptoms of citrate-induced hypocalcemia include perioral tingling, finger and toe paresthesias, muscle cramps, and in severe cases, tetany and cardiac arrhythmias (QT prolongation). The appropriate nursing action is to slow or pause the procedure, notify the physician, check ionized calcium level, and administer IV calcium gluconate as ordered. Calcium chloride can also be used but is more irritating to peripheral veins." },
      { question: "Which finding on pulmonary function testing is PARADOXICALLY increased during active diffuse alveolar hemorrhage and is considered diagnostically significant?", options: ["Forced expiratory volume in 1 second (FEV1)","Total lung capacity (TLC)","Diffusing capacity for carbon monoxide (DLCO)","Peak expiratory flow rate (PEFR)"], correct: 2, rationale: "The DLCO is paradoxically INCREASED during active DAH because hemoglobin from extravasated red blood cells within the alveolar spaces avidly binds carbon monoxide used in the test. This extra-capillary hemoglobin artificially increases the measured CO uptake, raising the DLCO above baseline. This is the ONLY clinical condition where an acutely rising DLCO is a pathological finding rather than an improvement. In virtually all other pulmonary diseases, DLCO is either normal or decreased. A DLCO increase >30% above baseline during suspected DAH strongly supports the diagnosis." }
    ]
  },

  "digoxin-toxicity-rn": {
    title: "Digoxin Toxicity",
    cellular: { title: "Pathophysiology of Cardiac Glycoside Toxicity and Na+/K+-ATPase Inhibition", content: "Digoxin toxicity is a potentially fatal adverse drug reaction resulting from excessive accumulation of digoxin (a cardiac glycoside derived from the foxglove plant Digitalis purpurea) in the body, producing dangerous cardiac arrhythmias, severe gastrointestinal symptoms, and characteristic neurological manifestations. Digoxin remains a commonly prescribed medication for heart failure with reduced ejection fraction and for ventricular rate control in atrial fibrillation, but it has an extremely narrow therapeutic index (therapeutic range 0.5-2.0 ng/mL, with toxicity increasingly likely above 2.0 ng/mL), making toxicity a persistent clinical concern. The fundamental mechanism of digoxin at the cellular level involves inhibition of the Na+/K+-ATPase (sodium-potassium pump), a transmembrane enzyme present in virtually all human cells that actively transports three sodium ions out of the cell and two potassium ions into the cell with each cycle, using ATP hydrolysis as the energy source. Digoxin binds to the extracellular alpha subunit of the Na+/K+-ATPase and locks the pump in a phosphorylated state, preventing the conformational change necessary for potassium binding and transport. This inhibition has profound consequences in cardiomyocytes due to the intimate coupling between sodium, calcium, and potassium handling. When Na+/K+-ATPase is inhibited by digoxin, intracellular sodium concentration rises because sodium is no longer being efficiently pumped out. The elevated intracellular sodium reduces the electrochemical gradient that drives the sodium-calcium exchanger (NCX), a secondary active transporter that normally uses the sodium gradient to extrude one calcium ion from the cell in exchange for three sodium ions entering. With reduced sodium extrusion by the pump and diminished NCX activity, intracellular calcium accumulates. At therapeutic digoxin levels, this modest increase in intracellular calcium enhances the force of myocardial contraction (positive inotropy) by providing more calcium to bind troponin C and activate the actin-myosin cross-bridge cycling apparatus, producing the desired hemodynamic benefit in heart failure. However, in digoxin toxicity, the excessive inhibition of Na+/K+-ATPase causes dangerous intracellular calcium overload. The sarcoplasmic reticulum (SR) becomes saturated with calcium and begins to spontaneously release calcium during diastole through ryanodine receptors (RyR2), generating delayed afterdepolarizations (DADs). When DADs reach threshold, they trigger ectopic beats and life-threatening arrhythmias. The hallmark arrhythmia of digoxin toxicity is the combination of enhanced automaticity (from DADs) with impaired conduction (from direct effects on the AV node and from hyperkalemia). Digoxin toxicity enhances automaticity in atrial, junctional, and ventricular tissues while simultaneously slowing conduction through the AV node (vagomimetic effect) and the His-Purkinje system (direct Na+/K+-ATPase inhibition in conduction tissue). This combination produces the pathognomonic arrhythmia of digoxin toxicity: bidirectional ventricular tachycardia, where the QRS axis alternates between two directions beat-to-beat, reflecting alternating foci of triggered activity in the right and left bundle branches. Other characteristic arrhythmias include atrial tachycardia with AV block (enhanced atrial automaticity combined with AV nodal conduction delay), accelerated junctional rhythm (enhanced junctional automaticity), and regularization of the ventricular response in atrial fibrillation (which normally has an irregularly irregular rhythm -- regularization indicates complete AV block with a junctional escape rhythm). Acute digoxin toxicity (massive single ingestion, often intentional) presents differently from chronic digoxin toxicity (gradual accumulation over days to weeks, often in elderly patients with declining renal function). Acute toxicity produces severe hyperkalemia because Na+/K+-ATPase inhibition in all cells reduces potassium uptake from the extracellular space, and the hyperkalemia itself exacerbates cardiac toxicity and may cause fatal ventricular fibrillation. Chronic toxicity more commonly presents with insidious GI symptoms (anorexia, nausea, vomiting), neurological symptoms (confusion, visual disturbances including xanthopsia -- a characteristic yellow-green visual discoloration -- and halos around lights), and cardiac arrhythmias. Chronic toxicity is often precipitated by factors that increase digoxin levels or enhance its effects: renal impairment (digoxin is 70% renally excreted), hypokalemia (reduced extracellular potassium increases digoxin binding to Na+/K+-ATPase), hypomagnesemia (magnifies electrophysiological toxicity), hypercalcemia (synergistic calcium overload), hypothyroidism (decreased digoxin clearance), advanced age, low body weight, and drug interactions (amiodarone, verapamil, quinidine, and macrolide antibiotics all raise digoxin levels by inhibiting P-glycoprotein-mediated renal secretion or displacing digoxin from tissue binding sites)." },
    riskFactors: ["Renal impairment (digoxin is 70% renally excreted; declining GFR causes accumulation -- elderly patients with age-related renal decline are at highest risk; serum creatinine may be 'normal' with significantly reduced GFR in elderly, low-muscle-mass patients)","Hypokalemia (low extracellular potassium increases digoxin binding affinity to Na+/K+-ATPase -- digoxin and potassium compete for the same binding site on the pump; common causes include loop/thiazide diuretics, vomiting, diarrhea)","Hypomagnesemia (magnifies the electrophysiological effects of digoxin toxicity; commonly coexists with hypokalemia; diuretic therapy is a frequent cause)","Advanced age >70 years (reduced renal clearance, lower lean body mass producing higher tissue concentrations, increased sensitivity to digoxin at lower serum levels)","Drug interactions that raise digoxin levels (amiodarone increases digoxin level by 70-100%; verapamil increases by 50-75%; quinidine increases by 100%; clarithromycin/erythromycin increase by 40-70%; all inhibit P-glycoprotein or renal tubular secretion)","Hypothyroidism (decreased renal clearance and reduced volume of distribution increase digoxin levels; thyroid function should be checked when initiating digoxin)","Low body weight and decreased lean body mass (digoxin distributes to skeletal muscle; patients with low muscle mass have higher serum concentrations at standard doses)"],
    diagnostics: ["Serum digoxin level (therapeutic range 0.5-2.0 ng/mL; toxicity increasingly likely >2.0 ng/mL; draw level at least 6 hours after last dose to allow distribution -- levels drawn earlier give falsely elevated results; in chronic toxicity, levels may be only mildly elevated or even within 'therapeutic' range in elderly patients)","12-lead ECG with continuous telemetry monitoring (look for characteristic patterns: bidirectional VT, atrial tachycardia with AV block, accelerated junctional rhythm, regularized ventricular response in atrial fibrillation, ST depression with 'reverse tick' or 'Salvador Dali mustache' pattern; any NEW arrhythmia in a patient on digoxin should raise suspicion)","Serum potassium level (hyperkalemia in acute toxicity from Na+/K+-ATPase inhibition; hypokalemia as a precipitating factor in chronic toxicity; potassium >5.5 mEq/L in acute digoxin poisoning predicts life-threatening arrhythmias and need for Digibind)","Serum magnesium level (hypomagnesemia potentiates digoxin toxicity and must be corrected; low magnesium makes arrhythmias refractory to treatment)","Serum creatinine and BUN with calculated GFR (renal function determines digoxin clearance; acute kidney injury or chronic kidney disease causes drug accumulation)","Serum calcium level (hypercalcemia synergistically increases intracellular calcium overload with digoxin, worsening toxicity)","Basic metabolic panel with electrolytes (comprehensive assessment of metabolic factors affecting digoxin toxicity -- K+, Mg2+, Ca2+, renal function, acid-base status)"],
    management: ["Digoxin-specific antibody fragments (Digibind/DigiFab) for life-threatening toxicity (binds free digoxin with high affinity, forming inactive digoxin-Fab complexes that are renally excreted; indications: life-threatening arrhythmias, hyperkalemia >5.5 mEq/L in acute toxicity, hemodynamic instability, serum digoxin >10 ng/mL or ingestion >10 mg in adults)","Atropine 0.5-1.0 mg IV for symptomatic bradycardia and high-degree AV block (blocks vagal effects on AV node, improving conduction; may repeat every 3-5 minutes to maximum 3 mg; temporary bridge while Digibind takes effect)","Correct hypokalemia cautiously (potassium replacement IV to maintain K+ 4.0-5.0 mEq/L in chronic toxicity -- replacement reduces digoxin binding to Na+/K+-ATPase; do NOT give potassium in acute toxicity with hyperkalemia; rate should not exceed 10-20 mEq/hour via central line)","Correct hypomagnesemia (magnesium sulfate 2g IV over 15-30 minutes -- magnesium correction is essential as hypomagnesemia makes digoxin-toxic arrhythmias refractory to all other treatments)","Activated charcoal 50g if acute ingestion within 1-2 hours (reduces GI absorption; digoxin also undergoes enterohepatic recirculation, so cholestyramine can be considered for chronic toxicity)","Avoid electrical cardioversion unless absolutely necessary and at lowest effective energy (digoxin-toxic myocardium is hypersensitive to electrical stimulation; cardioversion can trigger refractory ventricular fibrillation; if cardioversion is unavoidable, start at 10-25 joules)"],
    nursingActions: ["Place patient on continuous cardiac telemetry monitoring and have defibrillator at bedside -- digoxin toxicity can cause sudden lethal arrhythmias; report any new arrhythmia or rhythm change immediately to the provider","Assess and document cardiac rhythm pattern: specifically evaluate for bidirectional VT (alternating QRS axis), atrial tachycardia with block, accelerated junctional rhythm, and regularization of AF; compare to baseline rhythm strips","Monitor serum potassium, magnesium, and calcium levels before and during treatment -- hypokalemia and hypomagnesemia MUST be corrected to resolve digoxin-induced arrhythmias; hold potassium replacement in acute toxicity with hyperkalemia","Administer Digibind/DigiFab as ordered: reconstitute per manufacturer instructions; infuse IV over 30 minutes (cardiac arrest: may give as bolus); have epinephrine available for rare anaphylaxis; monitor for clinical response within 30-60 minutes (improving rhythm, resolving GI symptoms)","Hold all further digoxin doses and notify the prescribing provider; verify that no additional digoxin is scheduled in the medication administration record or available at the bedside","Assess for GI symptoms of toxicity (anorexia is often the FIRST symptom, followed by nausea, vomiting, abdominal pain, diarrhea); monitor intake and output; provide antiemetics as ordered","Assess visual symptoms (ask specifically about yellow-green vision changes/xanthopsia, blurred vision, halos around lights, and photophobia -- these are characteristic neurological manifestations of digoxin toxicity)","Monitor serum digoxin levels after Digibind administration -- standard digoxin immunoassays measure TOTAL digoxin (free + Fab-bound) and will be FALSELY elevated after Digibind; free digoxin levels require special assay; clinical response is the best guide to treatment effectiveness"],
    assessmentFindings: ["Gastrointestinal symptoms (anorexia is typically the earliest symptom, followed by nausea, vomiting, abdominal pain, and diarrhea -- present in 80% of chronic toxicity cases)","Visual disturbances including xanthopsia (yellow-green color vision changes -- historically described as the 'yellow vision' seen in some of Van Gogh's later paintings), halos around lights, blurred vision, and photophobia","Cardiac arrhythmias (virtually any arrhythmia can occur; most characteristic: bidirectional VT, atrial tachycardia with AV block, accelerated junctional rhythm, sinus bradycardia, complete heart block)","Neurological symptoms (fatigue, malaise, confusion, delirium -- especially common in elderly patients with chronic toxicity; may be attributed to aging or dementia rather than recognized as drug toxicity)","Regularization of ventricular response in atrial fibrillation (the normally irregularly irregular rhythm becomes regular, suggesting complete AV block with junctional escape rhythm -- this is a critical finding that should trigger immediate digoxin level assessment)","Hyperkalemia in acute toxicity (from systemic Na+/K+-ATPase inhibition; potassium >5.5 mEq/L is an indication for Digibind; may present with muscle weakness and peaked T waves on ECG)","ECG changes: ST-segment depression with 'reverse tick' or 'scooped' appearance (Salvador Dali mustache pattern) -- this reflects digoxin effect (not necessarily toxicity) but its presence confirms digoxin is pharmacologically active"],
    signs: { left: ["Mild anorexia and nausea without vomiting","Digoxin level 2.0-2.5 ng/mL with normal sinus rhythm","Occasional premature ventricular contractions (PVCs) on telemetry","Mild fatigue attributed to underlying heart failure","Subtle color perception changes not yet recognized by patient"], right: ["Bidirectional ventricular tachycardia causing hemodynamic collapse","Complete heart block with ventricular rate <30 bpm unresponsive to atropine","Massive acute ingestion with digoxin level >10 ng/mL and potassium >6.5 mEq/L","Ventricular fibrillation refractory to defibrillation (digoxin-sensitized myocardium)","Cardiovascular collapse requiring Digibind and emergent transcutaneous pacing"] },
    medications: [
      { name: "Digoxin-specific antibody fragments (Digibind/DigiFab)", type: "Digoxin-specific antidote (monoclonal antibody Fab fragments)", action: "Digibind and DigiFab are purified Fab (antigen-binding) fragments derived from anti-digoxin antibodies produced in immunized sheep. These Fab fragments bind free (unbound) digoxin in the plasma and interstitial fluid with an affinity approximately 10 times greater than digoxin's affinity for the Na+/K+-ATPase, effectively pulling digoxin off its receptor sites on the pump. The resulting digoxin-Fab complex is pharmacologically inactive (too large to bind Na+/K+-ATPase) and is eliminated renally with a half-life of 15-20 hours. Clinical response begins within 20-30 minutes of IV administration, with complete reversal of toxicity typically within 1-4 hours. Each vial of DigiFab binds approximately 0.5 mg of digoxin. Dosing is calculated based on the total body load of digoxin: for known acute ingestion, dose (vials) = amount ingested (mg) x 0.8 / 0.5; for elevated steady-state levels, dose = serum digoxin (ng/mL) x weight (kg) / 100. In cardiac arrest from digoxin toxicity, empiric 10-20 vials may be given as IV bolus.", sideEffects: "Hypokalemia (as Na+/K+-ATPase function is restored, potassium shifts back into cells -- monitor potassium closely after Digibind and replace as needed); worsening heart failure (removal of digoxin's inotropic effect in patients who were on digoxin for heart failure); allergic reactions including anaphylaxis (rare; derived from sheep antibodies -- skin test can be performed but delays treatment); rapid atrial fibrillation (loss of digoxin's rate-controlling effect on AV node)", contra: "Known allergy to sheep proteins or papain (papain is used in Fab fragment production); use caution in patients with renal failure (digoxin-Fab complexes are renally cleared and may accumulate); relatively contraindicated for mild toxicity without life-threatening features (Fab fragments are expensive and removing digoxin may worsen underlying cardiac condition)", pearl: "After Digibind/DigiFab administration, standard digoxin immunoassays measure TOTAL digoxin (free + Fab-bound) and will show FALSELY elevated levels for days to weeks -- do NOT re-dose based on total digoxin levels; clinical response (rhythm improvement, symptom resolution) is the gold standard for assessing treatment adequacy; monitor potassium closely after Fab administration because rapid correction of Na+/K+-ATPase function shifts potassium intracellularly, causing hypokalemia that may itself be dangerous; rebound toxicity can occur 12-24 hours later as Fab fragments are cleared faster than tissue-bound digoxin is mobilized" },
      { name: "Atropine sulfate", type: "Anticholinergic/parasympatholytic (muscarinic receptor antagonist for bradyarrhythmias)", action: "Atropine competitively blocks acetylcholine at muscarinic (M2) receptors in the sinoatrial (SA) node, atrioventricular (AV) node, and other cardiac parasympathetic targets. By blocking the vagal (parasympathetic) influence on the heart, atropine increases the SA node firing rate (chronotropy), increases AV node conduction velocity (dromotropy), and shortens the AV node refractory period. In digoxin toxicity, part of the mechanism producing bradycardia and AV block is digoxin's vagomimetic effect (enhanced parasympathetic tone on the heart), which atropine directly antagonizes. Atropine is used as a temporizing measure for symptomatic bradycardia and high-degree AV block while definitive therapy with Digibind is being prepared or taking effect.", sideEffects: "Tachycardia (excessive vagal blockade); urinary retention (particularly in elderly men with BPH); dry mouth and decreased secretions; mydriasis and cycloplegia (blurred near vision); constipation and ileus; confusion and agitation (especially in elderly -- central anticholinergic syndrome); hyperthermia (impaired sweating)", contra: "Tachyarrhythmias (atropine will worsen heart rate); narrow-angle glaucoma (mydriasis can precipitate acute angle closure); obstructive uropathy; myasthenia gravis (may worsen weakness); use with caution in acute coronary syndrome (tachycardia increases myocardial oxygen demand)", pearl: "Atropine dose for digoxin-toxic bradycardia is 0.5-1.0 mg IV push, repeated every 3-5 minutes to a maximum of 3 mg total; doses less than 0.5 mg may cause PARADOXICAL BRADYCARDIA through central vagal stimulation; atropine may be ineffective for bradycardia caused by digoxin's DIRECT effects on conduction tissue (not vagally mediated) -- if atropine fails, do NOT cardiovert (risk of refractory VF); proceed to Digibind and transcutaneous pacing; atropine is a BRIDGE only -- it does not address the fundamental toxicity" },
      { name: "Magnesium sulfate", type: "Electrolyte replacement (antiarrhythmic adjunct for digoxin toxicity)", action: "Magnesium sulfate serves dual roles in digoxin toxicity management. First, it replaces magnesium that is frequently depleted by concurrent diuretic therapy (loop and thiazide diuretics waste both potassium and magnesium). Hypomagnesemia potentiates digoxin toxicity by multiple mechanisms: magnesium normally inhibits calcium influx through L-type calcium channels, stabilizes resting membrane potential, and is required for proper Na+/K+-ATPase function. Without adequate magnesium, intracellular calcium overload from digoxin is magnified, DADs are more easily triggered, and arrhythmias become refractory to other treatments. Second, magnesium has direct membrane-stabilizing and antiarrhythmic properties: it suppresses DADs by reducing calcium channel conductance, stabilizes the resting membrane potential, and decreases automaticity in Purkinje fibers. In digoxin toxicity, magnesium is considered a first-line adjunct because correcting hypomagnesemia may resolve arrhythmias that would otherwise require Digibind.", sideEffects: "Hypotension (from vasodilation -- infuse slowly); bradycardia (excessive magnesium slows conduction); respiratory depression and loss of deep tendon reflexes (signs of magnesium excess -- check patellar reflex before repeat dosing); flushing, warmth, and diaphoresis during infusion; nausea; muscle weakness at high levels", contra: "Severe renal failure (magnesium is renally cleared; accumulation risk; use with extreme caution and monitor levels closely); heart block (magnesium can worsen conduction delay); myasthenia gravis (magnesium can precipitate myasthenic crisis by impairing neuromuscular transmission)", pearl: "Always check and correct magnesium BEFORE or concurrently with potassium replacement in digoxin toxicity -- hypomagnesemia makes hypokalemia refractory to potassium replacement (magnesium is required for the ROMK channel that retains potassium in the distal nephron); administer 2g MgSO4 IV over 15-30 minutes for acute arrhythmias, then 1-2g/hour infusion to maintain serum Mg >2.0 mg/dL; monitor deep tendon reflexes (loss of patellar reflex indicates excessive magnesium levels >7 mEq/L); the combination of hypokalemia AND hypomagnesemia in a patient on digoxin is an extremely high-risk scenario for lethal arrhythmias" }
    ],
    pearls: ["Bidirectional ventricular tachycardia (alternating QRS axis beat-to-beat) is virtually PATHOGNOMONIC for digoxin toxicity -- there are very few other causes of this specific arrhythmia pattern (catecholaminergic polymorphic VT is the main differential)","Hypokalemia potentiates digoxin toxicity because potassium and digoxin compete for the SAME binding site on the Na+/K+-ATPase alpha subunit -- when extracellular potassium is low, more digoxin binds to the pump, increasing toxicity even at 'therapeutic' serum levels","Regularization of the ventricular response in a patient with atrial fibrillation who is on digoxin should immediately raise suspicion for digoxin toxicity with complete AV block and junctional escape rhythm -- AF is defined by its irregular irregularity, and a regular rhythm means the AV node is no longer conducting atrial impulses","AVOID electrical cardioversion in digoxin toxicity unless it is an absolute last resort for hemodynamically unstable VT/VF unresponsive to Digibind -- the digoxin-toxic myocardium is hypersensitive to electrical stimulation, and cardioversion can trigger REFRACTORY ventricular fibrillation; if cardioversion is unavoidable, start at the lowest energy setting (10-25J)","After Digibind/DigiFab administration, monitor potassium closely for HYPOKALEMIA (opposite of acute toxicity) -- as Na+/K+-ATPase function is restored, potassium rapidly shifts back into cells; this post-Digibind hypokalemia may itself cause dangerous arrhythmias","Xanthopsia (yellow-green color vision) is the classic visual disturbance of digoxin toxicity -- art historians have speculated that Vincent van Gogh's prominent use of yellow in his later paintings may have been influenced by digoxin-related visual changes from foxglove treatment prescribed by his physician","Serum digoxin levels drawn less than 6 hours after the last dose are unreliable because digoxin has a large volume of distribution and requires 6-8 hours to reach distribution equilibrium -- early levels will be falsely elevated; always document the time of the last dose when ordering a level"],
    quiz: [
      { question: "A patient with atrial fibrillation on digoxin therapy is noted on telemetry to have a suddenly REGULAR ventricular rhythm at 52 bpm. What does this rhythm change most likely indicate?", options: ["Successful rate control with digoxin achieving the target heart rate","Spontaneous conversion from atrial fibrillation to normal sinus rhythm","Digoxin toxicity with complete AV block and junctional escape rhythm -- the normally irregular AF has become regular because the AV node is no longer conducting atrial impulses","Development of atrial flutter with fixed 2:1 AV conduction"], correct: 2, rationale: "Atrial fibrillation is defined by its irregularly irregular ventricular response. When a patient with AF who is taking digoxin develops a REGULAR rhythm (especially at a slow rate like 52 bpm), it strongly suggests that the AV node is no longer conducting the chaotic atrial impulses -- this is complete AV block from digoxin toxicity. The regular rhythm is a junctional escape rhythm (rate 40-60 bpm) that has taken over because the AV node is completely blocked. This is a critical finding requiring immediate digoxin level measurement and likely Digibind administration." },
      { question: "A patient is admitted with acute intentional digoxin ingestion. The serum potassium is 6.8 mEq/L. Which medication is the priority treatment?", options: ["IV potassium chloride to further replace potassium stores","Digoxin-specific antibody fragments (Digibind/DigiFab) to reverse Na+/K+-ATPase inhibition and allow potassium re-entry into cells","Calcium gluconate IV to stabilize the myocardium against hyperkalemia","Amiodarone to prevent arrhythmias from the hyperkalemia"], correct: 1, rationale: "In acute digoxin toxicity with significant hyperkalemia (K+ >5.5 mEq/L), Digibind/DigiFab is the priority treatment because it addresses the ROOT CAUSE of the hyperkalemia -- Na+/K+-ATPase inhibition preventing cellular potassium uptake. By removing digoxin from the pump, Digibind restores normal potassium handling and the hyperkalemia resolves as potassium shifts back into cells. Importantly, IV calcium is traditionally AVOIDED in digoxin toxicity because calcium supplementation may worsen the intracellular calcium overload that drives digoxin-toxic arrhythmias (though this contraindication is debated in recent literature for life-threatening hyperkalemia)." },
      { question: "An elderly patient on digoxin 0.125 mg daily and furosemide 40 mg daily reports loss of appetite, nausea, and seeing yellow halos around lights. The digoxin level is 1.8 ng/mL (within therapeutic range). What should the nurse recognize?", options: ["The symptoms are unrelated to digoxin because the level is within the therapeutic range","The patient likely has digoxin toxicity despite the 'therapeutic' level -- elderly patients can experience toxicity at lower serum concentrations, and the symptoms (anorexia, nausea, xanthopsia) are classic for chronic digoxin toxicity","The symptoms are side effects of furosemide, not digoxin, and do not require intervention","The yellow halos indicate a new ophthalmologic condition requiring eye specialist referral"], correct: 1, rationale: "Elderly patients frequently experience digoxin toxicity at serum levels within the 'therapeutic' range (0.5-2.0 ng/mL) due to decreased lean body mass, reduced renal clearance, and increased sensitivity to the drug. The classic triad of anorexia (often the earliest symptom), nausea, and xanthopsia (yellow-green visual changes/halos) is highly suggestive of chronic digoxin toxicity. Furthermore, this patient is on furosemide, which causes potassium and magnesium wasting -- hypokalemia and hypomagnesemia potentiate digoxin toxicity. The nurse should hold digoxin, check electrolytes (K+, Mg2+), notify the provider, and obtain an ECG." }
    ]
  },

  "discharge-readiness-rn": {
    title: "Discharge Readiness Assessment",
    cellular: { title: "Conceptual Framework of Discharge Readiness, Transitional Care, and Readmission Prevention", content: "Discharge readiness assessment is a systematic, evidence-based nursing process that evaluates a patient's physiological stability, functional capacity, knowledge, self-care ability, and support system adequacy to determine their preparedness for safe transition from the acute care hospital setting to the next level of care (home, rehabilitation facility, skilled nursing facility, or other post-acute setting). Discharge planning is not a single event occurring on the day of discharge but a continuous process that begins at admission and evolves throughout the hospital stay. Poor discharge preparation is a leading contributor to preventable hospital readmissions, with approximately 20% of Medicare patients readmitted within 30 days and an estimated 27% of those readmissions being potentially preventable with better discharge processes. The Hospital Readmissions Reduction Program (HRRP), established by the Affordable Care Act in 2012, imposes financial penalties on hospitals with excess readmission rates for specific conditions (heart failure, acute myocardial infarction, pneumonia, COPD, total hip/knee arthroplasty, and coronary artery bypass graft), creating significant institutional motivation to improve discharge processes. The conceptual framework for discharge readiness encompasses four domains that nursing assessment must address. The first domain is physiological stability, the foundational requirement confirming that the acute medical condition prompting hospitalization has been adequately treated and stabilized. This includes resolution or adequate management of the presenting illness, stable vital signs within acceptable parameters for the patient's baseline (recognizing that chronically ill patients may have different baseline values than the general population), adequate pain control with an oral or outpatient-appropriate analgesic regimen, stable laboratory values (electrolytes, renal function, hemoglobin, coagulation parameters), functional nutrition and hydration with demonstrated tolerance of oral intake, and stable wound healing without signs of surgical site infection. The second domain is functional capacity assessment, evaluating whether the patient can perform the activities of daily living (ADLs) and instrumental activities of daily living (IADLs) required for their discharge disposition. ADLs include bathing, dressing, toileting, transferring, continence management, and feeding. IADLs encompass more complex tasks such as medication management, meal preparation, transportation, financial management, housekeeping, and communication. Physical therapy, occupational therapy, and speech-language pathology assessments contribute to functional capacity evaluation, particularly for patients recovering from stroke, major surgery, prolonged immobility, or deconditioning. If functional deficits exceed what can be safely managed at the planned discharge disposition, the care team must arrange appropriate services (home health, outpatient rehabilitation) or modify the discharge disposition (discharge to rehabilitation facility or skilled nursing facility instead of home). The third domain is patient and caregiver knowledge and self-efficacy, arguably the most critical domain for preventing readmissions. Patients and their designated caregivers must demonstrate understanding of their diagnosis, the reason for hospitalization, their medication regimen (including new medications, changed medications, and discontinued medications), warning signs that should prompt return to the emergency department, activity restrictions, dietary modifications, wound care if applicable, follow-up appointment schedule, and when and how to contact their healthcare providers with concerns. The teach-back method is the gold standard educational technique for verifying patient understanding: the nurse explains a concept, then asks the patient to explain it back in their own words ('Tell me in your own words how you will take your new blood pressure medication'). If the patient cannot accurately teach back the information, the nurse must re-educate using different approaches until the patient demonstrates comprehension. Health literacy assessment is an essential component because approximately 36% of American adults have basic or below-basic health literacy, making it difficult for them to understand discharge instructions written at a high reading level. Discharge materials should be written at a 5th-6th grade reading level with clear, actionable language, use of visual aids, and avoidance of medical jargon. The fourth domain is environmental and social support assessment, evaluating whether the patient's home environment and support network can sustain safe recovery. This includes assessment of living situation (alone vs. with family/caregivers), home safety (stairs, bathroom accessibility, fall hazards), availability and willingness of caregivers, financial resources for medications and medical equipment, transportation for follow-up appointments, and access to food and nutrition. Medication reconciliation is a Joint Commission National Patient Safety Goal that must be completed at every care transition, including discharge. The process involves creating a comprehensive list of all medications the patient was taking prior to admission (including prescription medications, over-the-counter medications, supplements, and herbal remedies), comparing this list with medications ordered during hospitalization, and generating an accurate discharge medication list that accounts for new medications started, medications discontinued, and dose changes. Medication reconciliation errors are a leading cause of adverse drug events after discharge, occurring in up to 70% of patients at hospital transitions if reconciliation is not performed systematically." },
    riskFactors: ["Age >65 years (elderly patients have higher readmission rates due to multiple comorbidities, polypharmacy, functional decline during hospitalization, and limited social support)","Multiple chronic conditions/comorbidities (heart failure, COPD, diabetes, chronic kidney disease -- each additional comorbidity increases discharge complexity and readmission risk)","Low health literacy (approximately 36% of adults have basic or below-basic health literacy; unable to understand standard discharge instructions, medication labels, or follow-up requirements)","Polypharmacy (patients on >=5 medications have significantly higher risk of medication errors, adverse drug events, and non-adherence after discharge)","Social isolation and lack of caregiver support (patients living alone without available family or community support are at higher risk for falls, medication non-adherence, and missed follow-up appointments)","Prior hospitalization within 30 days (previous recent admission is one of the strongest predictors of readmission, suggesting inadequate resolution of the underlying condition or discharge process)","Mental health conditions including depression and cognitive impairment (depression reduces self-care motivation and adherence; cognitive impairment limits ability to follow discharge instructions independently)"],
    diagnostics: ["Discharge Readiness Assessment Tool (nurse-completed evaluation of physiological stability, functional capacity, knowledge, and psychosocial readiness -- validated instruments include the Readiness for Hospital Discharge Scale and the B-PREPARED scale)","Teach-back assessment of patient and caregiver knowledge (nurse asks patient to explain their diagnosis, medications, warning signs, and follow-up plan in their own words; inability to teach back accurately indicates need for additional education)","Functional capacity assessment using standardized tools (Barthel Index for ADLs, Katz Index of Independence, Timed Up and Go test for mobility, physical and occupational therapy evaluations)","Medication reconciliation review (comparison of pre-admission medication list, inpatient medications, and discharge medication list to identify discrepancies, new medications, discontinued medications, and potential interactions)","Health literacy screening (validated tools include the Newest Vital Sign, REALM-SF, and single-item literacy screener: 'How confident are you filling out medical forms by yourself?' -- identifies patients who need simplified education materials)","Fall risk assessment (Morse Fall Scale or Hendrich II; evaluates risk factors for falls in the home environment including gait instability, medication effects, environmental hazards)","Social determinants of health screening (assess food security, housing stability, transportation access, financial ability to obtain medications, caregiver availability -- unmet social needs are major contributors to readmission)"],
    management: ["Initiate discharge planning at admission (interdisciplinary team identifies anticipated discharge date, disposition, and barriers; early identification of needs allows time to arrange services such as home health, DME, outpatient therapy)","Complete medication reconciliation at discharge per Joint Commission National Patient Safety Goal (compare pre-admission medications with discharge orders; clearly communicate which medications are NEW, CHANGED, or DISCONTINUED; provide written medication list in patient-friendly format)","Implement structured teach-back education (explain each element of the discharge plan, then ask the patient to teach it back in their own words; re-educate and re-assess until patient demonstrates accurate understanding; document teach-back success in the medical record)","Arrange follow-up appointments before discharge (schedule primary care visit within 7 days of discharge for high-risk patients; specialist follow-up as indicated; provide patient with written appointment details including date, time, location, and provider name)","Coordinate post-discharge services (home health nursing, physical/occupational therapy, medical equipment delivery, pharmacy coordination for specialty medications, meals on wheels, transportation assistance)","Implement evidence-based transitional care interventions (Coleman Care Transitions Intervention, Project RED -- Re-Engineered Discharge, BOOST -- Better Outcomes by Optimizing Safe Transitions; these programs have demonstrated 20-30% reductions in 30-day readmissions)"],
    nursingActions: ["Perform discharge readiness assessment using validated tool 24-48 hours before anticipated discharge (assess physiological stability, functional capacity, knowledge, self-care ability, and psychosocial support; if deficits identified, develop action plan to address before discharge)","Conduct comprehensive medication reconciliation: review all pre-admission medications with patient, compare to discharge medications, identify and explain new medications (purpose, dose, frequency, side effects), discontinued medications (reason), and changed doses; provide written medication list in large print with patient-friendly language","Use teach-back method for ALL discharge education: explain each concept clearly, then ask 'Can you tell me in your own words how you will take your new medication?' or 'What symptoms would make you call the doctor or go to the emergency room?'; if patient cannot accurately teach back, re-educate using different approach (simpler language, visual aids, demonstration)","Assess patient and caregiver ability to perform required self-care tasks through direct observation: medication self-administration, blood glucose monitoring, wound care, ostomy care, self-injection technique, use of medical equipment (oxygen, CPAP, walker); arrange home health nursing if patient/caregiver cannot demonstrate competency","Provide written discharge instructions at appropriate health literacy level (5th-6th grade reading level; use simple language, short sentences, bullet points, and pictures; avoid medical jargon; translate into patient's primary language if English is not their first language)","Communicate discharge plan to receiving providers using structured handoff (SBAR format to primary care provider, home health agency, or receiving facility; include key diagnoses, active problems, new medications, pending results, and specific follow-up needs)","Screen for social determinants of health that may impede recovery: food insecurity, housing instability, inability to afford medications, lack of transportation to follow-up appointments, social isolation; connect patients with social work, case management, and community resources","Complete post-discharge phone call within 48-72 hours for high-risk patients (assess symptom status, medication adherence, understanding of follow-up plan, barriers encountered since discharge; this single intervention reduces 30-day readmissions by 20-30%)"],
    assessmentFindings: ["Physiological stability indicators (stable vital signs, adequate pain control with oral analgesics, tolerating oral intake, wound healing without infection, stable laboratory values)","Functional capacity observations (patient able to ambulate safely to bathroom and required distances, perform self-care activities, transfer safely between bed/chair/commode with or without appropriate assistive devices)","Knowledge demonstration through teach-back (patient accurately explains diagnosis, medication regimen, warning signs requiring emergency evaluation, follow-up appointment details, and self-care activities)","Psychosocial readiness indicators (patient expresses confidence in managing at home, caregiver demonstrates willingness and ability to assist with care needs, patient identifies community resources and support systems)","Barriers to discharge readiness (continued need for IV medications, inability to perform required self-care independently without arranged support, unresolved insurance/authorization for needed services or equipment, unsafe home environment)","Risk factors for readmission (LACE index components: Length of stay, Acuity of admission, Comorbidities, Emergency department visits in prior 6 months; high-risk patients require enhanced transitional care interventions)","Medication-related concerns (patient unable to afford prescribed medications, complex regimen exceeding patient's management ability, potential drug interactions identified during reconciliation)"],
    signs: { left: ["Patient demonstrates accurate teach-back of medication regimen and warning signs","Vital signs stable and within acceptable range for patient's baseline for 24+ hours","Patient ambulates independently or with appropriate assistive device to required functional distances","Adequate social support and safe home environment confirmed","Follow-up appointments scheduled and patient has transportation plan"], right: ["Patient unable to accurately teach back any component of discharge education after multiple attempts","Persistent physiological instability (ongoing IV medication requirements, unstable vital signs, acute pain uncontrolled with oral analgesics)","Significant functional decline from baseline requiring level of care not available at planned discharge disposition","No identified caregiver for patient requiring significant assistance with ADLs and medication management","Homeless or unsafe living situation with no alternative housing arrangement identified"] },
    medications: [
      { name: "Medication Reconciliation Process", type: "Patient safety intervention (systematic medication review at care transitions)", action: "Medication reconciliation is a structured process mandated by the Joint Commission as a National Patient Safety Goal that involves five steps at discharge: (1) Collecting a comprehensive Best Possible Medication History (BPMH) including all prescription medications, over-the-counter medications, vitamins, supplements, and herbal remedies the patient was taking prior to admission; (2) Comparing the BPMH with medications ordered during hospitalization to identify discrepancies (unintentional omissions, duplications, interactions); (3) Creating an accurate discharge medication list that reflects all intended changes; (4) Communicating the reconciled list to the patient and next provider of care; (5) Verifying patient understanding through teach-back. Medication reconciliation prevents adverse drug events that occur at care transitions, which affect up to 70% of patients when reconciliation is not performed. The most common errors include unintentional continuation of medications that should have been stopped, omission of chronic medications that should have been restarted, dose discrepancies, and therapeutic duplications.", sideEffects: "Incomplete reconciliation may result in adverse drug events including therapeutic duplications (patient takes both home medication and new hospital-prescribed medication with same mechanism), unintended omissions of chronic medications (patient stops taking essential medications without medical direction), drug interactions between new discharge medications and pre-existing medications, and overdose from dose confusion between pre-admission and discharge doses", contra: "There are no contraindications to medication reconciliation -- it should be performed for EVERY patient at EVERY care transition without exception; barriers include time constraints, incomplete medication histories, patient inability to recall medications, and lack of access to pharmacy records", pearl: "The most dangerous moment for medication errors is the care transition -- patients are often started on new medications in the hospital while some home medications are held; at discharge, the nurse must clearly communicate THREE categories: NEW medications (started in hospital, continue at home), CHANGED medications (dose or frequency altered), and STOPPED medications (discontinued, do not resume); provide this list in writing using patient-friendly language; always ask the patient to bring ALL medication bottles to the first follow-up appointment for verification" },
      { name: "Teach-Back Method", type: "Evidence-based health education technique (patient comprehension verification)", action: "The teach-back method (also called show-back, teach-to-goal, or closing the loop) is an evidence-based patient education technique endorsed by the Agency for Healthcare Research and Quality (AHRQ), the Joint Commission, and the National Quality Forum. The technique involves three steps: (1) The nurse explains a concept or instruction in clear, simple language avoiding medical jargon; (2) The nurse asks the patient to explain the concept back in their own words (not simply repeat the nurse's words) using non-shaming language such as 'I want to make sure I explained this clearly -- can you tell me in your own words how you will take this medication?'; (3) If the patient cannot accurately teach back, the nurse re-explains using a different approach and reassesses. Teach-back is repeated in cycles until the patient demonstrates accurate understanding. Research demonstrates that teach-back reduces 30-day readmission rates by 20-30%, improves medication adherence, increases patient satisfaction, and is effective across all health literacy levels and patient populations.", sideEffects: "Common barriers to effective teach-back include time constraints, patient fatigue or pain limiting attention span, cognitive impairment limiting retention, language barriers requiring interpreter services, and nurse discomfort with the technique (feeling that it 'tests' the patient); when patients feel judged or embarrassed by teach-back, they may disengage -- the nurse must frame teach-back as an assessment of the NURSE'S teaching effectiveness, not the patient's intelligence", contra: "There are no contraindications to teach-back -- it should be used universally for all discharge education; it is particularly critical for patients with low health literacy, complex medication regimens, new diagnoses, limited English proficiency, cognitive impairment (include caregiver), and conditions with high readmission rates", pearl: "Frame teach-back as a reflection of YOUR teaching, not a test of the patient's intelligence: say 'I want to make sure I did a good job explaining -- can you tell me...' rather than 'Do you understand?'; patients who respond 'yes' to 'Do you understand?' may not actually comprehend but are embarrassed to admit confusion; visual aids, demonstration, and written materials at 5th-grade reading level enhance teach-back effectiveness; document teach-back outcomes in the medical record (what was taught, patient's response, need for re-education)" },
      { name: "Post-Discharge Follow-Up Call", type: "Transitional care intervention (nurse-led telephone follow-up within 48-72 hours)", action: "The post-discharge follow-up phone call is an evidence-based transitional care intervention where a nurse contacts the patient by telephone within 48-72 hours of hospital discharge to assess their clinical status, verify medication adherence, troubleshoot barriers encountered since discharge, confirm follow-up appointments, and identify early warning signs of deterioration that could lead to emergency department visits or readmission. The structured call covers six domains: (1) Clinical status -- how the patient is feeling, any new or worsening symptoms; (2) Medication review -- is the patient taking all medications as prescribed, any difficulty obtaining medications, any side effects; (3) Understanding of discharge instructions -- teach-back of warning signs and self-care activities; (4) Follow-up appointments -- does the patient have scheduled appointments and plan to attend; (5) Equipment and services -- has home health, DME, and other ordered services been received; (6) Social needs -- any barriers to recovery including food, housing, transportation. Multiple randomized controlled trials demonstrate that structured post-discharge phone calls reduce 30-day readmissions by 20-30% and are one of the most cost-effective readmission prevention strategies available.", sideEffects: "Limitations include inability to reach patients by phone (disconnected numbers, wrong numbers, patients not answering), patient fatigue with medical system contact, difficulty assessing clinical status without physical examination, and potential for false reassurance if patient minimizes symptoms during the call; phone calls do not replace in-person follow-up but serve as a bridge during the high-risk early post-discharge period", contra: "No contraindications to post-discharge phone calls; all hospitalized patients benefit, with highest yield in patients with high readmission risk (heart failure, COPD, multiple comorbidities, low health literacy, limited social support); calls should be documented in the medical record and findings communicated to the outpatient care team", pearl: "The 48-72 hour post-discharge window is the highest-risk period for medication errors, symptom recurrence, and failed transitions; during the call, use specific screening questions: 'Have you been able to fill all your new prescriptions?', 'Can you tell me which medications you took this morning?', 'Have you had any new symptoms since leaving the hospital?', 'Do you know who to call if you have a problem?'; if concerning symptoms are identified, arrange expedited follow-up rather than defaulting to ED referral; document the call and any interventions in the electronic health record" }
    ],
    pearls: ["Discharge planning begins at ADMISSION, not on the day of discharge -- early identification of barriers (social support, home safety, functional limitations, insurance coverage) allows adequate time to arrange services and prevents last-minute discharge delays or unsafe discharges","The teach-back method is the single most effective technique for verifying patient understanding and reducing readmissions -- 'Do you understand?' is NEVER an acceptable substitute because patients routinely say 'yes' without true comprehension; always ask the patient to explain back in their own words","Medication reconciliation errors occur in up to 70% of care transitions when systematic reconciliation is not performed -- the three most dangerous categories are: therapeutic DUPLICATIONS (taking both home and new hospital medications), unintentional OMISSIONS (stopping chronic medications), and DOSE CONFUSION (continuing the hospital dose instead of the intended outpatient dose)","The 48-72 hour post-discharge phone call reduces readmissions by 20-30% and is one of the most cost-effective interventions available -- it catches medication errors, identifies early clinical deterioration, and reinforces discharge education during the highest-risk transition period","Health literacy affects approximately 36% of American adults and is often invisible -- patients with low health literacy may appear to understand, nod in agreement, and even say 'yes' when asked 'Do you understand?' while having no comprehension of the instructions; discharge materials should be written at a 5th-6th grade reading level with visual aids","The LACE index (Length of stay, Acuity of admission, Comorbidities, Emergency department visits in prior 6 months) predicts 30-day readmission risk and identifies patients who need enhanced transitional care interventions including home health nursing, structured phone follow-up, and expedited outpatient appointments","Social determinants of health (food insecurity, housing instability, inability to afford medications, lack of transportation) are among the strongest predictors of readmission and must be screened for and addressed before discharge -- connecting patients with social work and community resources is as important as clinical care"],
    quiz: [
      { question: "A nurse is preparing discharge instructions for a patient with newly diagnosed heart failure who has a 6th-grade education level. Which technique is most appropriate to verify the patient understands the discharge plan?", options: ["Ask the patient 'Do you have any questions about your discharge instructions?'","Provide written instructions at an 8th-grade reading level and have the patient sign acknowledging receipt","Use the teach-back method by asking the patient to explain in their own words when they should call the doctor or go to the emergency department","Give the instructions to the patient's family member instead of the patient because of the low education level"], correct: 2, rationale: "The teach-back method is the gold standard evidence-based technique for verifying patient understanding, particularly for patients with limited health literacy. By asking the patient to explain the discharge plan in their own words (not simply repeat the nurse's words), the nurse can assess actual comprehension and identify areas requiring re-education. Asking 'Do you have any questions?' is ineffective because patients with low health literacy often do not know what they do not understand. Instructions at an 8th-grade level are too complex. Bypassing the patient and giving instructions only to family members violates the patient's right to health education and autonomy." },
      { question: "During medication reconciliation at discharge, the nurse discovers that the patient's home medication of metformin 500 mg twice daily was not continued during hospitalization and is not on the discharge medication list. The patient has type 2 diabetes. What is the most appropriate nursing action?", options: ["Assume the medical team intentionally discontinued metformin and proceed with discharge without it","Contact the prescribing provider to clarify whether the omission of metformin was intentional or an unintentional reconciliation error before completing the discharge","Add metformin to the discharge medication list independently since the patient was taking it at home","Tell the patient to restart metformin on their own after discharge and discuss it with their primary care doctor"], correct: 1, rationale: "This is a classic medication reconciliation error -- an unintentional omission of a chronic medication during care transition. The nurse should NEVER assume an omission was intentional without verification. Metformin may have been appropriately held during hospitalization (for IV contrast, acute kidney injury, NPO status) but should typically be restarted at discharge if those conditions have resolved. The nurse should contact the prescribing provider to clarify intent, document the conversation, and ensure the reconciled discharge medication list accurately reflects all intended changes. Nurses cannot independently add prescription medications to the discharge list." },
      { question: "A 78-year-old patient with COPD, heart failure, and diabetes is being discharged home. He lives alone, his daughter visits weekly, and he manages 12 medications. During teach-back, he cannot accurately describe his new medications or warning signs. What is the nurse's priority intervention?", options: ["Discharge the patient on schedule with detailed written instructions and schedule a follow-up appointment","Identify this patient as high readmission risk and implement enhanced transitional care: arrange home health nursing, simplify and re-educate on the medication regimen until teach-back is successful, arrange the 48-hour post-discharge phone call, and involve the daughter in discharge education","Request a psychiatric consultation for the patient's inability to retain information","Extend the hospital stay by one week to provide additional education time"], correct: 1, rationale: "This patient has multiple high-risk factors for readmission: age >65, multiple comorbidities (COPD, HF, diabetes), polypharmacy (12 medications), lives alone with limited support, and failed teach-back assessment. The appropriate response is to implement enhanced transitional care interventions: (1) arrange home health nursing for medication management and clinical monitoring, (2) continue education using alternative approaches until teach-back is successful, (3) involve the daughter as backup caregiver in discharge education, (4) schedule the 48-72 hour post-discharge phone call, (5) arrange close outpatient follow-up within 3-7 days. Discharging with only written instructions for a patient who has failed teach-back is unsafe." }
    ]
  }
};

let ok = 0;
let fail = 0;
for (const [id, lesson] of Object.entries(lessons)) {
  if (inject(id, lesson)) ok++; else fail++;
}
console.log(`Done: ${ok} injected, ${fail} failed.`);
